 49→const val INITIATE_LOAD_MORE_OFFSET = 3
 50→const val PHOTON_WIDTH_QUALITY_RATION = 0.5 // load images in 1/2 screen width to save users' data
 51→const val FEATURED_IMAGE_HEIGHT_WIDTH_RATION = 0.56 // 9:16
 52→
 53→class ReaderDiscoverViewModel @Inject constructor(
 54→    private val postUiStateBuilder: ReaderPostUiStateBuilder,
 55→    private val readerPostMoreButtonUiStateBuilder: ReaderPostMoreButtonUiStateBuilder,
 56→    private val readerPostCardActionsHandler: ReaderPostCardActionsHandler,
 57→    private val readerDiscoverDataProvider: ReaderDiscoverDataProvider,
 58→    private val reblogUseCase: ReblogUseCase,
 59→    private val readerUtilsWrapper: ReaderUtilsWrapper,
 60→    private val readerTracker: ReaderTracker,
 61→    displayUtilsWrapper: DisplayUtilsWrapper,
 62→    private val getFollowedTagsUseCase: GetFollowedTagsUseCase,
 63→    private val readerImprovementsFeatureConfig: ReaderImprovementsFeatureConfig,
 64→    @Named(UI_THREAD) private val mainDispatcher: CoroutineDispatcher,
 65→    @Named(IO_THREAD) private val ioDispatcher: CoroutineDispatcher
 66→) : ScopedViewModel(mainDispatcher) {
 67→    private var isStarted = false
 68→
 69→    private lateinit var parentViewModel: ReaderViewModel
 70→
 71→    private val _uiState = MediatorLiveData<DiscoverUiState>()
 72→    val uiState: LiveData<DiscoverUiState> = _uiState
 73→
 74→    private val _navigationEvents = MediatorLiveData<Event<ReaderNavigationEvents>>()
 75→    val navigationEvents: LiveData<Event<ReaderNavigationEvents>> = _navigationEvents
 76→
 77→    private val _snackbarEvents = MediatorLiveData<Event<SnackbarMessageHolder>>()
 78→    val snackbarEvents: LiveData<Event<SnackbarMessageHolder>> = _snackbarEvents
 79→
 80→    private val _preloadPostEvents = MediatorLiveData<Event<PreLoadPostContent>>()
 81→    val preloadPostEvents: LiveData<Event<PreLoadPostContent>> = _preloadPostEvents
 82→
 83→    private val _scrollToTopEvent = MutableLiveData<Event<Unit>>()
 84→    val scrollToTopEvent: LiveData<Event<Unit>> = _scrollToTopEvent
 85→
 86→    /**
 87→     * Post which is about to be reblogged after the user selects a target site.
 88→     */
 89→    private var pendingReblogPost: ReaderPost? = null
 90→
 91→    private var swipeToRefreshTriggered = false
 92→
 93→    /**
 94→     * Don't recalculate the size after a device orientation change as it'd result in change of the url -> it wouldn't
 95→     * use cached images.
 96→     */
 97→    private val photonWidth: Int = (displayUtilsWrapper.getDisplayPixelWidth() * PHOTON_WIDTH_QUALITY_RATION).toInt()
 98→    private val photonHeight: Int = (photonWidth * FEATURED_IMAGE_HEIGHT_WIDTH_RATION).toInt()
 99→
100→    private val communicationChannelObserver = Observer { data: Event<ReaderDiscoverCommunication>? ->
101→        data?.let {
102→            data.getContentIfNotHandled()?.let {
103→                handleDataProviderEvent(it)
104→            }
105→        }
106→    }
107→
108→    fun start(parentViewModel: ReaderViewModel) {
109→        if (isStarted) return
110→        isStarted = true
111→        this.parentViewModel = parentViewModel
112→        init()
113→    }
114→
115→    private fun init() {
116→        // Start with loading state
117→        _uiState.value = DiscoverUiState.LoadingUiState
118→
119→        readerPostCardActionsHandler.initScope(viewModelScope)
120→
121→        // Get the correct repository
122→        readerDiscoverDataProvider.start()
123→
124→        observeDiscoverFeed()
125→        observeFollowStatus()
126→
127→        // TODO reader improvements: Consider using Channel/Flow
128→        readerDiscoverDataProvider.communicationChannel.observeForever(communicationChannelObserver)
129→
130→        _navigationEvents.addSource(readerPostCardActionsHandler.navigationEvents) { event ->
131→            val target = event.peekContent()
132→            if (target is ShowSitePickerForResult) {
133→                pendingReblogPost = target.post
134→            }
135→            _navigationEvents.value = event
136→        }
137→
138→        _snackbarEvents.addSource(readerPostCardActionsHandler.snackbarEvents) { event ->
139→            _snackbarEvents.value = event
140→        }
141→
142→        _preloadPostEvents.addSource(readerPostCardActionsHandler.preloadPostEvents) { event ->
143→            _preloadPostEvents.value = event
144→        }
145→    }
146→
147→    private fun observeDiscoverFeed() {
148→        // listen to changes to the discover feed
149→        _uiState.addSource(readerDiscoverDataProvider.discoverFeed) { posts ->
150→            launch {
151→                val userTags = getFollowedTagsUseCase.get()
152→                if (userTags.isEmpty()) {
153→                    _uiState.value = DiscoverUiState.EmptyUiState.ShowNoFollowedTagsUiState {
154→                        parentViewModel.onShowReaderInterests()
155→                    }
156→                } else {
157→                    if (posts != null && posts.cards.isNotEmpty()) {
158→                        _uiState.value = DiscoverUiState.ContentUiState(
159→                            convertCardsToUiStates(posts),
160→                            reloadProgressVisibility = false,
161→                            loadMoreProgressVisibility = false,
162→                        )
163→                        if (swipeToRefreshTriggered) {
164→                            _scrollToTopEvent.postValue(Event(Unit))
165→                            swipeToRefreshTriggered = false
166→                        }
167→                    } else {
168→                        _uiState.value = DiscoverUiState.EmptyUiState.ShowNoPostsUiState {
169→                            _navigationEvents.value = Event(ShowReaderSubs)
170→                        }
171→                    }
172→                }
173→            }
174→        }
175→    }
176→
177→    private fun observeFollowStatus() {
178→        // listen to changes on follow status for updating the reader recommended blogs state immediately
179→        _uiState.addSource(readerPostCardActionsHandler.followStatusUpdated) { data ->
180→            val currentUiState: DiscoverUiState.ContentUiState = _uiState.value as? DiscoverUiState.ContentUiState
181→                ?: return@addSource
182→            val mutableCards = currentUiState.cards.toMutableList()
183→            var hasChangedCards = false
184→
185→            for (i in mutableCards.indices) {
186→                val card = mutableCards[i] as? ReaderCardUiState.ReaderRecommendedBlogsCardUiState ?: continue
187→                val mutableBlogs = card.blogs.toMutableList()
188→                var hasChangedBlogs = false
189→
190→                for (j in mutableBlogs.indices) {
191→                    val blog = mutableBlogs[j]
192→                    if (blog.blogId == data.blogId && blog.feedId == data.feedId) {
193→                        mutableBlogs[j] = blog.copy(isFollowed = data.following, isFollowEnabled = data.isChangeFinal)
194→                        hasChangedBlogs = true
195→                    }
196→                }
197→
198→                if (hasChangedBlogs) {
199→                    mutableCards[i] = card.copy(blogs = mutableBlogs)
200→                    hasChangedCards = true
201→                }
202→            }
203→
204→            if (hasChangedCards) {
205→                _uiState.value = currentUiState.copy(cards = mutableCards)
206→            }
207→        }
208→    }
209→
210→    private suspend fun convertCardsToUiStates(posts: ReaderDiscoverCards): List<ReaderCardUiState> {
211→        return posts.cards.map { card ->
212→            when (card) {
213→                is ReaderPostCard -> if (readerImprovementsFeatureConfig.isEnabled()) {
214→                    postUiStateBuilder.mapPostToNewUiState(
215→                        source = ReaderTracker.SOURCE_DISCOVER,
216→                        post = card.post,
217→                        photonWidth = photonWidth,
218→                        photonHeight = photonHeight,
219→                        postListType = TAG_FOLLOWED,
220→                        onButtonClicked = this@ReaderDiscoverViewModel::onButtonClicked,
221→                        onItemClicked = this@ReaderDiscoverViewModel::onPostItemClicked,
222→                        onItemRendered = this@ReaderDiscoverViewModel::onItemRendered,
223→                        onMoreButtonClicked = this@ReaderDiscoverViewModel::onMoreButtonClickedNew,
224→                        onMoreDismissed = this@ReaderDiscoverViewModel::onMoreMenuDismissedNew,
225→                        onVideoOverlayClicked = this@ReaderDiscoverViewModel::onVideoOverlayClicked,
226→                        onPostHeaderViewClicked = this@ReaderDiscoverViewModel::onPostHeaderClicked,
227→                    )
228→                } else {
229→                    postUiStateBuilder.mapPostToUiState(
230→                        source = ReaderTracker.SOURCE_DISCOVER,
231→                        post = card.post,
232→                        isDiscover = true,
233→                        photonWidth = photonWidth,
234→                        photonHeight = photonHeight,
235→                        onButtonClicked = this@ReaderDiscoverViewModel::onButtonClicked,
236→                        onItemClicked = this@ReaderDiscoverViewModel::onPostItemClicked,
237→                        onItemRendered = this@ReaderDiscoverViewModel::onItemRendered,
238→                        onDiscoverSectionClicked = this@ReaderDiscoverViewModel::onDiscoverClicked,
239→                        onMoreButtonClicked = this@ReaderDiscoverViewModel::onMoreButtonClicked,
240→                        onMoreDismissed = this@ReaderDiscoverViewModel::onMoreMenuDismissed,
241→                        onVideoOverlayClicked = this@ReaderDiscoverViewModel::onVideoOverlayClicked,
242→                        onPostHeaderViewClicked = { onPostHeaderClicked(card.post.postId, card.post.blogId) },
243→                        onTagItemClicked = this@ReaderDiscoverViewModel::onTagItemClicked,
244→                        postListType = TAG_FOLLOWED
245→                    )
246→                }
247→                is InterestsYouMayLikeCard -> {
248→                    postUiStateBuilder.mapTagListToReaderInterestUiState(
249→                        card.interests,
250→                        this@ReaderDiscoverViewModel::onReaderTagClicked
251→                    )
252→                }
253→                is ReaderRecommendedBlogsCard -> {
254→                    postUiStateBuilder.mapRecommendedBlogsToReaderRecommendedBlogsCardUiState(
255→                        recommendedBlogs = card.blogs,
256→                        onItemClicked = this@ReaderDiscoverViewModel::onRecommendedSiteItemClicked,
257→                        onFollowClicked = this@ReaderDiscoverViewModel::onFollowSiteClicked
258→                    )
259→                }
260→            }
261→        }
262→    }
263→
264→    private fun handleDataProviderEvent(it: ReaderDiscoverCommunication) {
265→        when (it) {
266→            is Started -> {
267→                handleStartedEvent(it)
268→            }
269→            is Success -> {
270→            } // no op
271→            is Error ->
272→                handleErrorEvent()
273→        }
274→    }
275→
276→    private fun handleStartedEvent(it: ReaderDiscoverCommunication) {
277→        uiState.value.let { state ->
278→            if (state is DiscoverUiState.ContentUiState) {
279→                when (it.task) {
280→                    REQUEST_FIRST_PAGE -> {
281→                        _uiState.value = state.copy(reloadProgressVisibility = true)
282→                    }
283→                    REQUEST_MORE -> {
284→                        _uiState.value = state.copy(loadMoreProgressVisibility = true)
285→                    }
286→                }
287→            } else {
288→                _uiState.value = DiscoverUiState.LoadingUiState
289→            }
290→        }
291→    }
292→
293→    private fun handleErrorEvent() {
294→        _uiState.value?.let { uiState ->
295→            when (uiState) {
296→                is DiscoverUiState.LoadingUiState -> {
297→                    // show fullscreen error
298→                    _uiState.value = DiscoverUiState.EmptyUiState.RequestFailedUiState { onRetryButtonClick() }
299→                }
300→                is DiscoverUiState.ContentUiState -> {
301→                    _uiState.value = uiState.copy(
302→                        reloadProgressVisibility = false,
303→                        loadMoreProgressVisibility = false
304→                    )
305→                    // show snackbar
306→                    _snackbarEvents.postValue(
307→                        Event(
308→                            SnackbarMessageHolder(
309→                                UiStringRes(R.string.reader_error_request_failed_title)
310→                            )
311→                        )
312→                    )
313→                }
314→                is DiscoverUiState.EmptyUiState.RequestFailedUiState -> Unit // Do nothing
315→                is DiscoverUiState.EmptyUiState.ShowNoFollowedTagsUiState -> Unit // Do nothing
316→                is DiscoverUiState.EmptyUiState.ShowNoPostsUiState -> Unit // Do nothing
317→            }
318→        }
319→    }
