408→    private fun findPost(postId: Long, blogId: Long): ReaderPost? {
409→        return readerDiscoverDataProvider.discoverFeed.value?.cards?.let {
410→            it.filterIsInstance<ReaderPostCard>()
411→                .find { card -> card.post.postId == postId && card.post.blogId == blogId }
412→                ?.post
413→        }
414→    }
415→
416→    private fun initiateLoadMoreIfNecessary(item: ReaderCardUiState) {
417→        (uiState.value as? DiscoverUiState.ContentUiState)?.cards?.let {
418→            val closeToEndIndex = it.size - INITIATE_LOAD_MORE_OFFSET
419→            if (closeToEndIndex > 0) {
420→                val isCardCloseToEnd: Boolean = it.getOrNull(closeToEndIndex) == item
421→                if (isCardCloseToEnd) {
422→                    readerTracker.track(AnalyticsTracker.Stat.READER_DISCOVER_PAGINATED)
423→                    launch(ioDispatcher) { readerDiscoverDataProvider.loadMoreCards() }
424→                }
425→            }
426→        }
427→    }
