481→
482→    private fun replaceUiStateItem(before: ReaderCardUiState, after: ReaderCardUiState) {
483→        (_uiState.value as? DiscoverUiState.ContentUiState)?.let {
484→            val updatedList = it.cards.toMutableList()
485→            val index = it.cards.indexOf(before)
486→            if (index != -1) {
487→                updatedList[index] = after
488→                _uiState.value = it.copy(cards = updatedList)
489→            }
490→        }
491→    }
