393→    private fun List<MenuElementData>.filterSingleItems(): List<MenuElementData.Item.Single> {
394→        val singleItems = mutableListOf<MenuElementData.Item.Single>()
395→        forEach {
396→            if (it is MenuElementData.Item.Single) {
397→                singleItems.add(it)
398→            } else if (it is MenuElementData.Item.SubMenu) {
399→                singleItems.addAll(it.children.filterIsInstance<MenuElementData.Item.Single>())
400→            }
401→        }
402→        return singleItems
403→    }
