 22→/**
 23→ * tbl_tags stores the list of tags the user subscribed to or has by default
 24→ */
 25→public class ReaderTagTable {
 26→    protected static void createTables(SQLiteDatabase db) {
 27→        db.execSQL("CREATE TABLE tbl_tags ("
 28→                   + " tag_slug TEXT COLLATE NOCASE,"
 29→                   + " tag_display_name TEXT COLLATE NOCASE,"
 30→                   + " tag_title TEXT COLLATE NOCASE,"
 31→                   + " tag_type INTEGER DEFAULT 0,"
 32→                   + " endpoint TEXT,"
 33→                   + " date_updated TEXT,"
 34→                   + " PRIMARY KEY (tag_slug, tag_type)"
 35→                   + ")");
 36→    }
 37→
 38→    protected static void dropTables(SQLiteDatabase db) {
 39→        db.execSQL("DROP TABLE IF EXISTS tbl_tags");
 40→    }
 41→
 42→    /*
 43→     * returns true if tbl_tags is empty
 44→     */
 45→    public static boolean isEmpty() {
 46→        return (SqlUtils.getRowCount(ReaderDatabase.getReadableDb(), "tbl_tags") == 0);
 47→    }
 48→
 49→    /*
 50→     * replaces all tags with the passed list
 51→     */
 52→    public static void replaceTags(ReaderTagList tags) {
 53→        if (tags == null || tags.size() == 0) {
 54→            return;
 55→        }
 56→
 57→        SQLiteDatabase db = ReaderDatabase.getWritableDb();
 58→        db.beginTransaction();
 59→        try {
 60→            try {
 61→                // first delete all existing tags, then insert the passed ones
 62→                db.execSQL("DELETE FROM tbl_tags");
 63→                addOrUpdateTags(tags);
 64→                db.setTransactionSuccessful();
 65→            } catch (SQLException e) {
 66→                AppLog.e(T.READER, e);
 67→            }
 68→        } finally {
 69→            db.endTransaction();
 70→        }
 71→    }
 72→
 73→    /*
 74→     * similar to the above but only replaces followed tags
 75→     */
 76→    public static void replaceFollowedTags(ReaderTagList tags) {
 77→        if (tags == null || tags.size() == 0) {
 78→            return;
 79→        }
 80→
 81→        SQLiteDatabase db = ReaderDatabase.getWritableDb();
 82→        db.beginTransaction();
 83→        try {
 84→            try {
 85→                // first delete all existing followed tags, then insert the passed ones
 86→                String[] args = {Integer.toString(ReaderTagType.FOLLOWED.toInt())};
 87→                db.execSQL("DELETE FROM tbl_tags WHERE tag_type=?", args);
 88→                addOrUpdateTags(tags);
 89→                db.setTransactionSuccessful();
 90→            } catch (SQLException e) {
 91→                AppLog.e(T.READER, e);
 92→            }
 93→        } finally {
 94→            db.endTransaction();
 95→        }
 96→    }
 97→
 98→    public static void addOrUpdateTag(ReaderTag tag) {
 99→        if (tag == null) {
100→            return;
101→        }
102→        ReaderTagList tags = new ReaderTagList();
103→        tags.add(tag);
104→        addOrUpdateTags(tags);
105→    }
106→
107→    public static void addOrUpdateTags(ReaderTagList tagList) {
108→        if (tagList == null || tagList.size() == 0) {
109→            return;
110→        }
111→        SQLiteStatement stmt = null;
112→        try {
113→            stmt = ReaderDatabase.getWritableDb().compileStatement(
114→                    "INSERT OR REPLACE INTO tbl_tags (tag_slug, tag_display_name, tag_title, tag_type, endpoint) "
115→                    + "VALUES (?1,?2,?3,?4,?5)");
116→
117→            for (ReaderTag tag : tagList) {
118→                stmt.bindString(1, tag.getTagSlug());
119→                stmt.bindString(2, tag.getTagDisplayName());
120→                stmt.bindString(3, tag.getTagTitle());
121→                stmt.bindLong(4, tag.tagType.toInt());
122→                stmt.bindString(5, tag.getEndpoint());
123→                stmt.execute();
124→            }
125→        } finally {
126→            SqlUtils.closeStatement(stmt);
127→        }
128→    }
129→
130→    /*
131→     * returns true if the passed tag exists, regardless of type
132→     */
133→    public static boolean tagExists(ReaderTag tag) {
134→        if (tag == null) {
135→            return false;
136→        }
137→        String[] args = {tag.getTagSlug(), Integer.toString(tag.tagType.toInt())};
138→        return SqlUtils.boolForQuery(ReaderDatabase.getReadableDb(),
139→                                     "SELECT 1 FROM tbl_tags WHERE tag_slug=?1 AND tag_type=?2",
140→                                     args);
141→    }
142→
143→    /*
144→     * returns true if the passed tag exists and it has the passed type
145→     */
146→    private static boolean tagExistsOfType(String tagSlug, ReaderTagType tagType) {
147→        if (TextUtils.isEmpty(tagSlug) || tagType == null) {
148→            return false;
149→        }
150→
151→        String[] args = {tagSlug, Integer.toString(tagType.toInt())};
152→        return SqlUtils.boolForQuery(ReaderDatabase.getReadableDb(),
153→                                     "SELECT 1 FROM tbl_tags WHERE tag_slug=?1 AND tag_type=?2",
154→                                     args);
155→    }
156→
157→    public static boolean isFollowedTagName(String tagSlug) {
158→        return tagExistsOfType(tagSlug, ReaderTagType.FOLLOWED);
159→    }
